parameters.text:
=Sen profesyonel bir dijital medya içerik üreticisisin.

## HABER BİLGİLERİ
Başlık: {{ $json.title }}
Kaynak: {{ $json.source_name || $json.source }}
Özet: {{ $json.summary }}
Kategori: {{ $json.category }}
Marka Sesi: {{ $json.brand_voice || 'Bilgilendirici, güvenilir' }}

## İSTENEN ÇIKTILAR
Aşağıdaki formatta JSON çıktısı üret:

{
  "article": {
    "title": "SEO uyumlu başlık (max 70 karakter)",
    "slug": "url-friendly-slug",
    "content": "800-1200 kelimelik SEO uyumlu makale. Alt başlıklar (H2, H3) kullan. Paragraflar kısa ve okunaklı olsun.",
    "meta_description": "Meta açıklama (max 160 karakter)",
    "word_count": 1000
  },
  "social": {
    "twitter_post": "BPT tarzı Twitter/X paylaşımı (max 280 karakter). Vurucu başlık + ana nokta + çıkarım + hashtagler",
    "instagram_carousel": [
      "Slayt 1: Kapak metni (max 30 kelime)",
      "Slayt 2: Ana bilgi metni",
      "Slayt 3: Detay/arka plan",
      "Slayt 4: Etki/neden önemli",
      "Slayt 5: Kapanış + CTA"
    ],
    "linkedin_post": "Profesyonel LinkedIn paylaşımı (max 1000 karakter)"
  },
  "seo": {
    "keywords": ["anahtar kelime 1", "anahtar kelime 2", "anahtar kelime 3", "anahtar kelime 4", "anahtar kelime 5"],
    "reading_time_minutes": 5
  }
}

## KURALLAR
- Türkçe yaz
- Marka sesine uygun ton kullan
- SEO uyumlu başlık ve meta açıklama
- Gerçekçi ve doğru bilgiler
- Telif hakkı ihlali yok
- Clickbait değil, bilgilendirici
- Sadece JSON çıktısı ver, başka hiçbir şey yazma

parameters.jsCode:
// AI çıktısını parse et ve yapılandır
const results = [];

for (const item of $input.all()) {
  try {
    const aiOutput = item.json.output || item.json;
    const content = typeof aiOutput === 'string' ? JSON.parse(aiOutput) : aiOutput;

    const article = content.article || {};
    const social = content.social || {};
    const seo = content.seo || {};

    results.push({
      json: {
        news_id: item.json.id || item.json.news_id,
        title: article.title || item.json.title,
        slug: article.slug || article.title?.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, ''),
        article: article.content || '',
        meta_description: article.meta_description || '',
        word_count: article.word_count || (article.content ? article.content.split(/\s+/).length : 0),
        reading_time: seo.reading_time_minutes || Math.ceil((article.content || '').split(/\s+/).length / 200),
        twitter_post: social.twitter_post || '',
        instagram_carousel: JSON.stringify(social.instagram_carousel || []),
        linkedin_post: social.linkedin_post || '',
        seo_keywords: JSON.stringify(seo.keywords || []),
        category: item.json.category,
        status: 'draft',
        version: 1
      }
    });
  } catch (e) {
    console.error('İçerik parse hatası:', e.message, 'Haber ID:', item.json.id);
    // Hata olsa bile minimum veri ile devam et
    results.push({
      json: {
        news_id: item.json.id || item.json.news_id,
        title: item.json.title,
        slug: (item.json.title || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, ''),
        article: item.json.summary || '',
        meta_description: item.json.summary?.substring(0, 160) || '',
        word_count: (item.json.summary || '').split(/\s+/).length,
        reading_time: 1,
        twitter_post: item.json.title || '',
        instagram_carousel: '[]',
        linkedin_post: '',
        seo_keywords: '[]',
        category: item.json.category,
        status: 'draft',
        version: 1
      }
    });
  }
}

console.log(`${results.length} içerik üretildi ve yapılandırıldı`);
return results;
